const input = $('Workflow Input').item.json;

// Priority emoji mapping
const priorityEmoji = {
  'high': '🔴',
  'medium': '🟡',
  'low': '🟢'
};

const emoji = priorityEmoji[input.priority] || '🟡';
const priorityText = {
  'high': 'WYSOKI',
  'medium': 'ŚREDNI',
  'low': 'NISKI'
}[input.priority] || 'ŚREDNI';

const timestamp = new Date().toLocaleString('pl-PL', {
  dateStyle: 'short',
  timeStyle: 'short'
});

const slackMessage = {
  text: `${emoji} *Eskalacja z czatu AI*`,
  blocks: [
    {
      type: 'header',
      text: {
        type: 'plain_text',
        text: `${emoji} Eskalacja z czatu AI`,
        emoji: true
      }
    },
    {
      type: 'section',
      fields: [
        {
          type: 'mrkdwn',
          text: `*Priorytet:*\n${priorityText}`
        },
        {
          type: 'mrkdwn',
          text: `*Sesja:*\n${input.session_id || 'Nieznana'}`
        }
      ]
    },
    {
      type: 'section',
      text: {
        type: 'mrkdwn',
        text: `*Powód eskalacji:*\n${input.reason}`
      }
    },
    {
      type: 'section',
      text: {
        type: 'mrkdwn',
        text: `*Podsumowanie rozmowy:*\n${input.summary}`
      }
    },
    {
      type: 'context',
      elements: [
        {
          type: 'mrkdwn',
          text: `Czas: ${timestamp}`
        }
      ]
    },
    {
      type: 'divider'
    }
  ]
};

// Response time based on priority
const responseTime = {
  'high': '30 minut',
  'medium': '2 godzin',
  'low': '4 godzin'
}[input.priority] || '2 godzin';

return [{
  json: {
    slack_message: slackMessage,
    escalated: true,
    priority: input.priority,
    reason: input.reason,
    response_time: responseTime,
    session_id: input.session_id
  }
}];

// In production, this would be replaced with actual Slack node
// For demo purposes, we just log the notification

const input = $input.item.json;

console.log('=== SLACK NOTIFICATION ===');
console.log(JSON.stringify(input.slack_message, null, 2));
console.log('========================');

// Return success response for the agent
return [{
  json: {
    escalated: true,
    success: true,
    message: `Przekazałem Twoją sprawę do naszego zespołu obsługi klienta. Konsultant skontaktuje się z Tobą w ciągu ${input.response_time}. Dziękuję za cierpliwość.`,
    priority: input.priority,
    estimated_response: input.response_time,
    session_id: input.session_id,
    notification_sent: true
  }
}];
